"use client";

import { useEffect, useState, Suspense } from "react";
import { useSearchParams, useRouter } from "next/navigation";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { useBatchPolling, type BatchStatus, type ProductJobStatus } from "@/hooks/use-batch-polling";
import { apiPost, handleApiError } from "@/lib/api";
import { toast } from "sonner";
import {
  Clock,
  Loader2,
  CheckCircle2,
  XCircle,
  ArrowLeft,
  Film,
  RefreshCw,
  Layers,
  X,
} from "lucide-react";
import { EmptyState } from "@/components/empty-state";
import {
  DEFAULT_CODEX_MODEL,
  DEFAULT_SCRIPT_AI_PROVIDER,
} from "@/lib/script-ai";

// Status badge config
function getStatusBadge(status: ProductJobStatus["status"]) {
  switch (status) {
    case "queued":
      return (
        <Badge variant="outline" className="text-muted-foreground">
          <Clock className="h-3 w-3 mr-1" />
          Queued
        </Badge>
      );
    case "processing":
      return (
        <Badge variant="secondary" className="text-amber-500">
          <Loader2 className="h-3 w-3 mr-1 animate-spin" />
          Processing
        </Badge>
      );
    case "completed":
      return (
        <Badge className="bg-success/10 text-success border border-success/20 hover:bg-success/10">
          <CheckCircle2 className="h-3 w-3 mr-1" />
          Completed
        </Badge>
      );
    case "failed":
      return (
        <Badge variant="destructive">
          <XCircle className="h-3 w-3 mr-1" />
          Failed
        </Badge>
      );
  }
}

function getProgressValue(job: ProductJobStatus): number {
  switch (job.status) {
    case "queued":
      return 0;
    case "processing": {
      const parsed = parseInt(job.progress);
      return isNaN(parsed) ? 0 : parsed;
    }
    case "completed":
      return 100;
    case "failed":
      return 0;
  }
}

// Per-product card
function ProductJobCard({ job }: { job: ProductJobStatus }) {
  const progressValue = getProgressValue(job);

  return (
    <Card className={job.status === "completed" ? "border-success/50" : job.status === "failed" ? "border-destructive/50" : ""}>
      <CardHeader className="pb-2">
        <div className="flex items-start justify-between gap-2">
          <CardTitle className="text-sm font-medium leading-tight line-clamp-2">
            {job.title || job.product_id}
          </CardTitle>
          {getStatusBadge(job.status)}
        </div>
      </CardHeader>
      <CardContent className="space-y-2">
        <Progress value={progressValue} className="h-1.5" />
        {job.status === "failed" && job.error && (
          <p className="text-xs text-destructive break-words">{job.error}</p>
        )}
        {job.status === "processing" && (
          <p className="text-xs text-muted-foreground">{job.progress}</p>
        )}
      </CardContent>
    </Card>
  );
}

// Parse batch settings from URL search params (set by products page)
function parseBatchSettings(params: URLSearchParams) {
  return {
    voiceover_mode: params.get("vm") || "quick",
    tts_provider: params.get("tts") || "edge",
    duration_s: parseInt(params.get("dur") || "30") || 30,
    encoding_preset: params.get("enc") || "tiktok",
    cta_text: params.get("cta") || "Comanda acum!",
    voice_id: params.get("voice") || null,
    ai_provider: params.get("ai") || DEFAULT_SCRIPT_AI_PROVIDER,
    codex_model: params.get("cm") || DEFAULT_CODEX_MODEL,
    source: params.get("src") || "feed",
    enable_denoise: params.get("denoise") === "1",
    enable_sharpen: params.get("sharpen") === "1",
    enable_color_correction: params.get("cc") === "1",
  };
}

// Rebuild settings params string for retry redirect
function buildSettingsParams(settings: ReturnType<typeof parseBatchSettings>): string {
  const p = new URLSearchParams();
  if (settings.voiceover_mode !== "quick") p.set("vm", settings.voiceover_mode);
  if (settings.tts_provider !== "edge") p.set("tts", settings.tts_provider);
  if (settings.duration_s !== 30) p.set("dur", String(settings.duration_s));
  if (settings.encoding_preset !== "tiktok") p.set("enc", settings.encoding_preset);
  if (settings.cta_text !== "Comanda acum!") p.set("cta", settings.cta_text);
  if (settings.voice_id) p.set("voice", settings.voice_id);
  if (settings.ai_provider !== DEFAULT_SCRIPT_AI_PROVIDER) p.set("ai", settings.ai_provider);
  if (settings.codex_model !== DEFAULT_CODEX_MODEL) p.set("cm", settings.codex_model);
  if (settings.source !== "feed") p.set("src", settings.source);
  if (settings.enable_denoise) p.set("denoise", "1");
  if (settings.enable_sharpen) p.set("sharpen", "1");
  if (settings.enable_color_correction) p.set("cc", "1");
  return p.toString();
}

// Main content — reads search params
function BatchGenerateContent() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const batchId = searchParams.get("batch_id");
  const batchSettings = parseBatchSettings(searchParams);

  const [retryLoading, setRetryLoading] = useState(false); // Bug #131: useState for UI reactivity

  const { startPolling, stopPolling, isPolling, batchStatus, productJobs, completedCount, failedCount, totalCount } =
    useBatchPolling({
      interval: 2000,
      onBatchComplete: (status: BatchStatus) => {
        if (status.failed === 0) {
          toast.success(`All ${status.total} videos generated successfully!`);
        } else {
          toast.warning(`${status.completed} of ${status.total} videos complete. ${status.failed} failed.`);
        }
      },
    });

  // Start polling when batch_id is present (Bug #159: cleanup on unmount)
  useEffect(() => {
    if (batchId) {
      startPolling(batchId);
    }
    return () => { stopPolling(); };
  }, [batchId, startPolling, stopPolling]);

  // Retry failed products
  const handleRetryFailed = async () => {
    if (retryLoading) return;
    setRetryLoading(true);

    const failedProductIds = productJobs
      .filter((j) => j.status === "failed")
      .map((j) => j.product_id);

    if (failedProductIds.length === 0) {
      setRetryLoading(false);
      return;
    }

    try {
      const res = await apiPost("/products/batch-generate", {
        product_ids: failedProductIds,
        source: batchSettings.source,
        voiceover_mode: batchSettings.voiceover_mode,
        tts_provider: batchSettings.tts_provider,
        voice_id: batchSettings.voice_id,
        ai_provider: batchSettings.ai_provider,
        codex_model: batchSettings.codex_model,
        duration_s: batchSettings.duration_s,
        encoding_preset: batchSettings.encoding_preset,
        cta_text: batchSettings.cta_text,
        enable_denoise: batchSettings.enable_denoise,
        enable_sharpen: batchSettings.enable_sharpen,
        enable_color_correction: batchSettings.enable_color_correction,
      });
      if (res.ok) {
        const data = await res.json();
        const settingsStr = buildSettingsParams(batchSettings);
        router.push(`/batch-generate?batch_id=${data.batch_id}${settingsStr ? "&" + settingsStr : ""}`);
      } else {
        const err = await res.json().catch(() => ({ detail: "Retry failed" }));
        toast.error(err.detail || "Retry failed");
      }
    } catch (error) {
      handleApiError(error, "Could not retry the batch");
    } finally {
      setRetryLoading(false);
    }
  };

  // Empty state — no batch_id in URL
  if (!batchId) {
    return (
      <div className="min-h-full bg-background flex items-center justify-center">
        <EmptyState
          icon={<Layers className="h-6 w-6" />}
          title="No batch generation"
          description="Select items and configure a batch generation."
          action={{ label: "Back to Library", onClick: () => { router.push("/product-library"); } }}
        />
      </div>
    );
  }

  const overallProgress =
    totalCount > 0
      ? Math.round(((completedCount + failedCount) / totalCount) * 100)
      : 0;

  const handleCancelBatch = async () => {
    if (batchId) {
      try {
        await apiPost(`/jobs/${batchId}/cancel`, {});
      } catch { /* best effort */ }
    }
    stopPolling();
  };

  const isDone = batchStatus?.status === "completed";
  const allSucceeded = isDone && failedCount === 0;
  const someFailedAndDone = isDone && failedCount > 0;

  return (
    <div className="min-h-full bg-background">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <div className="mb-8">
          <Link href="/product-library">
            <Button variant="ghost" size="sm" className="mb-4 -ml-2">
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back to Library
            </Button>
          </Link>
          <h1 className="text-3xl font-bold flex items-center gap-2">
            <Film className="h-8 w-8 text-primary" />
            Batch Generation
          </h1>
          <p className="text-muted-foreground mt-1 text-sm font-mono">
            Batch ID: {batchId}
          </p>
        </div>

        {/* Overall progress bar */}
        {batchStatus && (
          <div className="mb-8 p-6 bg-card border rounded-lg space-y-3">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <p className="font-semibold">
                  {completedCount} of {totalCount} complete
                  {failedCount > 0 && (
                    <span className="text-destructive ml-2">• {failedCount} failed</span>
                  )}
                </p>
                <p className="text-sm text-muted-foreground">
                  {isDone
                    ? allSucceeded
                      ? "All videos generated successfully"
                      : "Batch complete with some failures"
                    : isPolling
                    ? "Generating videos..."
                    : "Processing"}
                </p>
              </div>
              <div className="text-2xl font-bold text-primary">{overallProgress}%</div>
            </div>
            <Progress value={overallProgress} className="h-2" />

            {/* Cancel button while processing */}
            {isPolling && !isDone && (
              <div className="pt-2">
                <Button variant="destructive" size="sm" onClick={handleCancelBatch}>
                  <X className="h-4 w-4 mr-2" />
                  Stop Batch
                </Button>
              </div>
            )}

            {/* Completion actions */}
            {allSucceeded && (
              <div className="pt-2 flex gap-3">
                <Link href="/librarie">
                  <Button>
                    <CheckCircle2 className="h-4 w-4 mr-2" />
                    View in Library
                  </Button>
                </Link>
              </div>
            )}

            {someFailedAndDone && (
              <div className="pt-2 flex gap-3">
                <Button
                  variant="destructive"
                  onClick={handleRetryFailed}
                >
                  <RefreshCw className="h-4 w-4 mr-2" />
                  Retry {failedCount} Failed
                </Button>
                {completedCount > 0 && (
                  <Link href="/librarie">
                    <Button variant="outline">
                      <CheckCircle2 className="h-4 w-4 mr-2" />
                      View {completedCount} in Library
                    </Button>
                  </Link>
                )}
              </div>
            )}
          </div>
        )}

        {/* Loading state — no status yet */}
        {!batchStatus && (
          <div className="flex items-center justify-center py-20">
            <div className="text-center space-y-3">
              <Loader2 className="h-8 w-8 animate-spin text-muted-foreground mx-auto" />
              <p className="text-muted-foreground">Loading batch status...</p>
            </div>
          </div>
        )}

        {/* Per-product card grid */}
        {productJobs.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {productJobs.map((job) => (
              <ProductJobCard key={job.product_id} job={job} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// Page component — wraps content in Suspense (required by Next.js App Router for useSearchParams)
export default function BatchGeneratePage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-full bg-background flex items-center justify-center">
          <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
        </div>
      }
    >
      <BatchGenerateContent />
    </Suspense>
  );
}
